B.Qy=new A.j(2001,4,23,"1\ubd84\uae30 \uc2e4\uc801","\uc0bc\uc131\uc804\uc790, \ubc18\ub3c4\uccb4 \ubd88\ud669\uc5d0\ub3c4 1\ubd84\uae30 \ud751\uc790","\uba54\ubaa8\ub9ac \uac12\uc774 \uae09\ub77d\ud558\ub294 \uc640\uc911\uc5d0\ub3c4 \uc0bc\uc131\uc804\uc790\uac00 \ubd84\uae30 \ud751\uc790\ub97c \ub0c8\ub2e4. \uc704\uae30 \uc18d \uccb4\ub825\uc774 \ud655\uc778\ub410\ub2e4.","\ubd88\ud669\uc740 \uac15\ud55c \uae30\uc5c5\uacfc \uc57d\ud55c \uae30\uc5c5\uc744 \uac08\ub77c\ub193\uc2b5\ub2c8\ub2e4.",B.C)
