B.RR=new A.j(2001,6,28,"\ubc18\ub3c5\uc810","\ud56d\uc18c\ubc95\uc6d0, MS \uac15\uc81c\ubd84\ud560 \uba85\ub839 \ub4a4\uc9d1\ub2e4","\ubc95\uc6d0\uc774 \ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8 \ubd84\ud560 \uba85\ub839\uc744 \ud30c\uae30\ud588\ub2e4. \ub2e4\ub9cc \ub3c5\uc810 \uc0ac\uc2e4\uc740 \uadf8\ub300\ub85c \uc778\uc815\ub410\ub2e4.","\uaddc\uc81c \ub9ac\uc2a4\ud06c\uac00 \uac77\ud788\uba74 \uc8fc\uac00\ub294 \uc548\ub3c4\ud569\ub2c8\ub2e4.",B.k)
